import { useEffect, useState } from "react"
function Crypto() {
  let [cryptodata, changecryptodata] = useState()
  useEffect(() => {
    async function fetchcoins() {
      let date = new Date() 
      let currentdate = date.getFullYear() + "-" + date.getMonth() + 1 + "-" + date.getDate()
      console.log(currentdate)
      const date2 = new Date();
      date2.setDate(date2.getDate() - 7);
      let pastdate = date2.getFullYear() + "-" + date2.getMonth() + 1 + "-" + date2.getDate()
      console.log(pastdate)
      let cryptodataarr = ["btc-bitcoin", "eth-ethereum", "bnb-bnb", "xrp-xrp", "sol-solana", "trx-tron"]
      let res = cryptodataarr.map(async(item) => {
        let fetched = await fetch(`https://api.coinpaprika.com/v1/tickers/${item}/historical?start=${pastdate}&end=${currentdate}&interval=1d`)
        let fetchedjson = await fetched.json()
        changecryptodata(fetchedjson)
      })

    }
    fetchcoins()
  }, [])
        useEffect(() => {
        console.log(cryptodata)
      }, [])
  return<>

  </>
}
export default Crypto
